<span class="line"><span style="color:#F9E2AF;font-style:italic;">            CommandResult</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">Continue</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">help_text</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">to_string</span><span style="color:#9399B2;">())</span></span>
